```class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long n = 1;
        for (int op : operations) {
            if (op == 0) n *= 2;
            else n = (n * 26) % 1000000007;
        }
        k %= n;
        char res = 'a';
        for (int op : operations) {
            if (op == 0) k /= 2;
            else {
                k = (k % 26) + (k / 26) * 25;
                res = (res - 'a' + 1) % 26 + 'a';
            }
        }
        return res;
    }
};
